INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Leadership & RH : Management d''équipe, résolution des conflits & motivation', 'Formation sur le management d’équipe, la motivation et la résolution des conflits pour renforcer la performance et la cohésion.', 5, 200000.00, 'entreprise', '2026-01-15', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Développer des compétences de leadership\n• Motiver et impliquer les collaborateurs\n• Identifier et résoudre les conflits efficacement\n• Optimiser la performance individuelle et collective\n• Renforcer la cohésion et l’engagement des équipes\n\n--- OBJECTIFS DÉTAILLÉS ---\nDévelopper des compétences de leadership, comprendre les mécanismes de motivation, gérer et résoudre les conflits, optimiser la performance et renforcer la cohésion d’équipe.\n\n--- PRÉREQUIS ---\nExpérience préalable en management ou gestion d’équipe souhaitée.\n\n--- CONTENU ---\nModule 1 : Introduction au leadership et au management\nModule 2 : Gestion et motivation d’équipe\nModule 3 : Communication efficace pour managers\nModule 4 : Gestion des conflits et résolution\nModule 5 : Leadership situationnel et prise de décision\nModule 6 : Développement de la cohésion d’équipe\nModule 7 : Atelier final – Plan d’action Leadership & RH\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nManagers commerciaux, responsables d’équipe, chefs de projet, responsables RH.\n\n--- MÉTHODES ---\nPrésentations interactives, études de cas, jeux de rôle, ateliers pratiques, simulations et mises en situation.\n\n--- SUPPORTS ---\nManuel du participant, fiches pratiques, modèles de plans de motivation et de résolution de conflits, supports PDF, slides et vidéos pédagogiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
